def longsighted_palindromic(siemens):
    if not siemens:
        return ""

    n = len(siemens)
    longest_palindrome = ""

    for i in range(n):
        for j in range(i, n):
            substring = siemens[i:j+1]
            if substring == substring[::-1] and len(substring) > len(longest_palindrome):
